// ============ Usage Example in ViewModel ============

package com.example.networking.example

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.networking.NetworkResult
import com.example.networking.model.UserProfile
import com.example.networking.repository.UserRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

class UserViewModel(
    private val userRepository: UserRepository = UserRepository()
) : ViewModel() {

    private val _usersState = MutableStateFlow<UsersUiState>(UsersUiState.Idle)
    val usersState: StateFlow<UsersUiState> = _usersState

    private val _userDetailState = MutableStateFlow<UserDetailUiState>(UserDetailUiState.Idle)
    val userDetailState: StateFlow<UserDetailUiState> = _userDetailState

    fun fetchUsers(page: Int = 1) {
        viewModelScope.launch {
            _usersState.value = UsersUiState.Loading
            when (val result = userRepository.getUsers(page)) {
                is NetworkResult.Success -> {
                    _usersState.value = UsersUiState.Success(result.data.data)
                }
                is NetworkResult.Error -> {
                    _usersState.value = UsersUiState.Error("Error ${result.code}: ${result.message}")
                }
                is NetworkResult.Exception -> {
                    _usersState.value = UsersUiState.Error(
                        result.throwable.localizedMessage ?: "Unknown error"
                    )
                }
            }
        }
    }

    fun fetchUserById(userId: Long) {
        viewModelScope.launch {
            _userDetailState.value = UserDetailUiState.Loading
            when (val result = userRepository.getUserById(userId)) {
                is NetworkResult.Success -> {
                    val user = result.data.data
                    if (user != null) {
                        _userDetailState.value = UserDetailUiState.Success(user)
                    } else {
                        _userDetailState.value = UserDetailUiState.Error("User not found")
                    }
                }
                is NetworkResult.Error -> {
                    _userDetailState.value = UserDetailUiState.Error("Error ${result.code}: ${result.message}")
                }
                is NetworkResult.Exception -> {
                    _userDetailState.value = UserDetailUiState.Error(
                        result.throwable.localizedMessage ?: "Unknown error"
                    )
                }
            }
        }
    }

    sealed class UsersUiState {
        object Idle : UsersUiState()
        object Loading : UsersUiState()
        data class Success(val users: List<UserProfile>) : UsersUiState()
        data class Error(val message: String) : UsersUiState()
    }

    sealed class UserDetailUiState {
        object Idle : UserDetailUiState()
        object Loading : UserDetailUiState()
        data class Success(val user: UserProfile) : UserDetailUiState()
        data class Error(val message: String) : UserDetailUiState()
    }
}